_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 uv1 = (vUv-.5);// * uAspect.xy;

vec2 uv6 = uv1;
float z = 12*(1+rand_preset)*length((abs(uv1.x)-abs(uv1.y)));
vec2 d = normalize(uv1);
vec2 rs = clamp(tan(z)*d,-4,4);
uv1 -= rs/40;

uv6 = .4*cos(uv1*8);
mus = .002/(length(uv6.y+uv6.x));
mus *= (1+roam_cos);

vec3 crisp= texture(sampler_main,uv1*(1-q28/12+.4*z)+.5);

vec3 ret1 = crisp + mus;

ret = (ret1*.99-.025);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((uv6.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q3         && ret.x<= q24*q1        )ret.y -= (noise9).x*.5;
if(ret.y> q22*q1         && ret.y<= q25*q2        )ret.z -= (noise9).y*.5;
if(ret.z> q23*q2         && ret.z<= q26*q3        )ret.x -= (noise9).z*.5;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 ac = vec2(q1,q2);
vec2 mu = vec2(q3,q4);
vec2 c = vec2(q5,q6);
vec2 d = vec2(q7,q8);

vec2 z = (vUv-0.5)*uAspect.wz;

// (c*z + d)
vec2 czd = vec2(z.x*c.x-z.y*c.y,z.x*c.y-z.y*c.x)*uAspect.yx + d;
// mu/(cz+d)
vec2 moebius = vec2( mu.x*czd.x + mu.y*czd.y , mu.y*czd.x-mu.x*czd.y )/(czd.x*czd.x+czd.y*czd.y) + ac;

    d = uTexSize.zw*4;
    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

moebius = 0.5 + (1.0 - abs( fract( moebius * 0.5  - vec2(dx.y,dy.y)*0.2 + vec2(dx.x,dy.x)*0.1) * 2 - 1.0 )-0.5)*0.99;

ret = tex2d(sampler_rand00, fract(moebius));
ret = mix(ret,-2,GetPixel(vUv + vec2(dx.y,dy.y)*0.1).x*0.1);
ret = mix(ret,-1,GetPixel(vUv - vec2(dx.z,dy.z)*0.024).z*0.4);
ret = mix(ret,1,clamp01(GetPixel(vUv).y-GetBlur3(vUv).y*2));
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((moebius.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q30
                     );
if(ret.x> q26*q3         && ret.x<= q23*q1        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q1         && ret.y<= q22*q2        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q2         && ret.z<= q21*q3        )ret.y -= (noise9).z*.5;

  fragColor = ret;
}
